import { comparePhi, getPhiTowerStep } from './bracketed-space';

console.log("Gnosis Bracketed Space: Phi Tower Refinement\n");
console.log("n | Bracket (Rational) | Sliver Width | Math.PHI Diff | Inside?");
console.log("--|--------------------|--------------|---------------|--------");

for (let n = 0; n < 10; n++) {
  const result = comparePhi(n);
  console.log(
    `${n.toString().padEnd(1)} | ` +
    `${result.bracket.padEnd(18)} | ` +
    `${result.width.toFixed(10)} | ` +
    `${result.diff.toFixed(10)} | ` +
    `${result.isInside}`
  );
}

const step5 = getPhiTowerStep(5);
const step6 = getPhiTowerStep(6);
console.log("\nRefinement check (Step 6 inside Step 5):");
const lowerOk = Number(step6.lower.num) / Number(step6.lower.den) >= Number(step5.lower.num) / Number(step5.lower.den);
const upperOk = Number(step6.upper.num) / Number(step6.upper.den) <= Number(step5.upper.num) / Number(step5.upper.den);
console.log(`Lower bound refined: ${lowerOk}`);
console.log(`Upper bound refined: ${upperOk}`);